ccess is found, DAMON\ninclude/linux/damon.h-738- * aggregates the information by increasing &damon_region->nr_accesses for\ninclude/linux/damon.h-739- * @aggr_interval time.  For each @aggr_interval, the count is reset.  DAMON\ninclude/linux/damon.h-740- * also checks whether the target memory regions need update (e.g., by\ninclude/linux/damon.h-741- * ``mmap()`` calls from the application, in case of virtual memory monitoring)\ninclude/linux/damon.h-742- * and applies the changes for each @ops_update_interval.  All time intervals\ninclude/linux/damon.h-743- * are in micro-seconds.  Please refer to &struct damon_operations and &struct\ninclude/linux/damon.h:744: * damon_call_control for more detail.\ninclude/linux/damon.h-745- */\ninclude/linux/damon.h-746-struct damon_attrs {\ninclude/linux/damon.h-747-\tunsigned long sample_interval;\ninclude/linux/damon.h-748-\tunsigned long aggr_interval;\ninclude/linux/damon.h-749-\tunsigned long ops_update_interval;\ninclude/linux/damon.h-750-\tstruct damon_intervals_goal intervals_goal;\ninclude/linux/damon.h-751-\tunsigned long min_nr_regions;\ninclude/linux/damon.h-752-\tunsigned long max_nr_regions;\ninclude/linux/damon.h-753-/* private: internal use only */\ninclude/linux/damon.h-754-\t/*\n--\ninclude/linux/damon.h-775- * damon_kdamond_pid().\ninclude/linux/damon.h-776- *\ninclude/linux/damon.h-777- * Once started, kdamond runs until explicitly required to be terminated or\ninclude/linux/damon.h-778- * every monitoring target is invalid.  The validity of the targets is checked\ninclude/linux/damon.h-779- * via the &damon_operations.target_valid of @ops.  The termination can also be\ninclude/linux/damon.h-780- * explicitly requested by calling damon_stop().  To know if a kdamond is\ninclude/linux/damon.h-781- * running, damon_is_running() can be used.\ninclude/linux/damon.h-782- *\ninclude/linux/damon.h-783- * While the kdamond is running, all accesses to &struct damon_ctx from a\ninclude/linux/damon.h-784- * thread other